  ('customs-7fec267e-moex-00388', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '對於一個採取固定匯率制度的國家，如果它的外國居民投資金額小於它的本國居民對外投資，若無 統計誤差，則該國的經常帳為 ，而資本與金融帳為 。', '["入超；淨資本流入", "出超；淨資本流出", "入超；淨資本流出", "出超與入超皆可能；淨資本流出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
