  ('customs-7fec267e-moex-00392', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設一國經濟原先處在長期均衡狀態下，根據總合供給與總合需求模型，當其政府恆常性調高對家 戶所課徵的定額稅時，在其他條件不變下：', '["短期均衡實質GDP會增加", "長期均衡實質GDP會減少", "短期均衡一般物價會上漲", "長期均衡名目GDP會減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
